import 'package:flutter/material.dart';
import 'package:shared_preferences/shared_preferences.dart';

class AuthManager {
  static final AuthManager _instance = AuthManager._internal();
  factory AuthManager() => _instance;

  AuthManager._internal();

  SharedPreferences? _prefs;
  String? _authToken;
  Map<String, dynamic>? _userData;

  Future<void> initPrefs() async {
    if (_prefs == null) {
      _prefs = await SharedPreferences.getInstance();
    }
  }

  Future<void> saveAuthToken(String token) async {
    await initPrefs();
    _prefs!.setString('auth_token', token);
    _authToken = token;
  }

  Future<void> saveUserData(Map<String, dynamic> data) async {
    await initPrefs();
    String userDataString = Map.from(data).toString(); // Convert map to string
    _prefs!.setString('user_data', userDataString);
    _userData = data;
  }

  String? get authToken => _authToken ?? _prefs?.getString('auth_token');

  Map<String, dynamic>? get userData {
    if (_userData != null) return _userData;

    String? userDataString = _prefs?.getString('user_data');
    if (userDataString != null) {
      // Convert string back to map
      try {
        _userData = jsonDecode(userDataString);
      } catch (e) {
        print("Error decoding user data: $e");
        return {};
      }
    }

    return _userData ?? {};
  }

  Future<void> clearAuth() async {
    await initPrefs();
    await _prefs!.remove('auth_token');
    await _prefs!.remove('user_data');
    _authToken = null;
    _userData = null;
  }
}